const BATTLE_SCENE_GD = `class_name BattleScene
extends Node2D

## ─── REGIONS ─────────────────────────────────────────────
## The battle scene orchestrates encounter flow:
## 1. Load encounter manifest
## 2. Spawn enemy sprites on grid
## 3. Initialize turn order
## 4. Run combat loop
## 5. Handle win/loss conditions

@onready var combat_hud: CombatHud = $CombatHud
@onready var sprite_container: Node2D = $SpriteContainer

var encounter_data: Dictionary = {}
var turn_queue: Array = []
var current_turn_index: int = 0

## ─── LIFECYCLE ───────────────────────────────────────────

func _ready() -> void:
	pass  # Encounter loaded externally via load_encounter()

## ─── ENCOUNTER LOADING ───────────────────────────────────

func load_encounter(manifest_path: String) -> void:
	var loader := EncounterLoader.new()
	encounter_data = loader.load_manifest(manifest_path)
	_spawn_enemies(encounter_data.get("enemies", []))

## ─── SPAWNING ────────────────────────────────────────────

func _spawn_enemies(enemies: Array) -> void:
	for enemy_def in enemies:
		var sprite := SpriteLoader.load_unit_sprite(
			enemy_def.get("sprite_pack", ""),
			enemy_def.get("facing", "front")
		)
		sprite.position = _grid_to_world(
			enemy_def.get("grid_pos", Vector2i.ZERO)
		)
		sprite_container.add_child(sprite)

## ─── GRID ────────────────────────────────────────────────

func _grid_to_world(grid_pos: Vector2i) -> Vector2:
	var cell_size := Vector2(64, 64)
	var offset := Vector2(128, 96)
	return offset + Vector2(grid_pos) * cell_size

## ─── TURN MANAGEMENT ────────────────────────────────────

func advance_turn() -> void:
	current_turn_index = (current_turn_index + 1) % turn_queue.size()

func get_current_unit() -> Dictionary:
	if turn_queue.is_empty():
		return {}
	return turn_queue[current_turn_index]
`;

