const SPRITE_LOADER_GD = `class_name SpriteLoader
extends RefCounted

## ─── REGIONS ─────────────────────────────────────────────
## Standard sprite loader for the battle scene.
## Resolves sprite pack paths and creates AnimatedSprite2D nodes.

## Direction mapping: 5 canonical -> 8 runtime
const DIR_MAP := {
	"front": "front",
	"front_34": "front_34",
	"side": "side",
	"back_34": "back_34",
	"back": "back",
	"front_mirror": "front_34",
	"side_mirror": "side",
	"back_mirror": "back_34",
}

static func load_unit_sprite(pack_path: String, facing: String) -> Sprite2D:
	var sprite := Sprite2D.new()
	var resolved_dir := DIR_MAP.get(facing, "front")
	var texture_path := "%s/%s.png" % [pack_path, resolved_dir]

	if ResourceLoader.exists(texture_path):
		sprite.texture = load(texture_path)
	else:
		# Placeholder circle for missing sprites
		sprite.texture = _create_placeholder()

	return sprite

static func _create_placeholder() -> ImageTexture:
	var img := Image.create(48, 48, false, Image.FORMAT_RGBA8)
	img.fill(Color(0.8, 0.2, 0.3, 0.7))
	return ImageTexture.create_from_image(img)
`;

const ENCOUNTER_LOADER_GD = `class_name EncounterLoader
extends RefCounted

## ─── REGIONS ─────────────────────────────────────────────
## Loads encounter manifest JSON files and returns structured
## encounter data for the battle scene.

func load_manifest(manifest_path: String) -> Dictionary:
	if not FileAccess.file_exists(manifest_path):
		push_error("Encounter manifest not found: %s" % manifest_path)
		return {}

	var file := FileAccess.open(manifest_path, FileAccess.READ)
	var json := JSON.new()
	var err := json.parse(file.get_as_text())

	if err != OK:
		push_error("Failed to parse manifest: %s" % json.get_error_message())
		return {}

	var data: Dictionary = json.data
	return _normalize(data)

func _normalize(raw: Dictionary) -> Dictionary:
	var result := {
		"encounter_id": raw.get("encounter_id", ""),
		"display_name": raw.get("display_name", "Unknown"),
		"grid_rows": raw.get("grid_rows", 3),
		"grid_cols": raw.get("grid_cols", 8),
		"enemies": [],
		"rules": raw.get("rules", []),
	}

	for enemy in raw.get("enemies", []):
		result["enemies"].append({
			"display_name": enemy.get("display_name", "Enemy"),
			"variant_id": enemy.get("variant_id", ""),
			"sprite_pack": enemy.get("sprite_pack", ""),
			"grid_pos": Vector2i(
				enemy.get("grid_col", 0),
				enemy.get("grid_row", 0)
			),
			"facing": enemy.get("facing", "front"),
		})

	return result
`;

