const GD_FILES: Array<{ relative: string; content: string }> = [
  { relative: 'project.godot', content: GODOT_PROJECT },
  { relative: 'battle/scenes/battle_scene.gd', content: BATTLE_SCENE_GD },
  { relative: 'battle/scenes/combat_hud.gd', content: COMBAT_HUD_GD },
  { relative: 'battle/scenes/sprite_loader.gd', content: SPRITE_LOADER_GD },
  { relative: 'battle/scenes/encounter_loader.gd', content: ENCOUNTER_LOADER_GD },
  { relative: 'tests/proof_harness.gd', content: PROOF_HARNESS_GD },
];

const DIRS = [
  'assets/sprites',
  'assets/portraits',
];

export function installRuntimeShell(
  _db: Database.Database,
  _projectId: string,
  godotRoot: string,
): InstallRuntimeResult {
  const paths: string[] = [];

  // Create directories
  for (const dir of DIRS) {
    const fullDir = path.join(godotRoot, dir);
    if (!fs.existsSync(fullDir)) {
      fs.mkdirSync(fullDir, { recursive: true });
    }
  }

  // Write GDScript files
  for (const file of GD_FILES) {
    const fullPath = path.join(godotRoot, file.relative);
    const dir = path.dirname(fullPath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
    fs.writeFileSync(fullPath, file.content, 'utf-8');
    paths.push(fullPath);
  }

  return { files_created: paths.length, paths };
}
